// Initialize SAM.gov contract query parameters
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
const formattedDate = sevenDaysAgo.toISOString().split('T')[0];

return [{
  json: {
    query_date: formattedDate,
    naics: process.env.PRIMARY_NAICS || '561720',
    page: 1,
    limit: 100,
    total_found: 0,
    processed_count: 0,
    timestamp: new Date().toISOString()
  }
}];

// Parse SAM.gov response and extract contract opportunities
const response = $node['Query SAM.gov API'].json || { opportunitiesData: [], totalRecords: 0 };

if (!response.opportunitiesData || response.opportunitiesData.length === 0) {
  return [{
    json: {
      records: [],
      total_count: 0,
      message: 'No contract opportunities found'
    }
  }];
}

const records = response.opportunitiesData.map((opp, idx) => ({
  json: {
    record_type: 'contract',
    index: idx + 1,
    legal_name: opp.title || opp.agencyName || 'Unknown',
    opportunity_id: opp.id || '',
    description: opp.description || '',
    naics: opp.naicsCode || '',
    agency: opp.agencyName || '',
    office: opp.officeAddress || '',
    contact_name: opp.contactName || '',
    contact_email: opp.email || '',
    contact_phone: opp.phone || '',
    deadline: opp.archiveDate || '',
    estimated_value: opp.estimatedAmount || 0,
    posted_date: opp.postedDate || '',
    type: opp.type || 'Solicitation',
    prime_contractor: opp.primeOrSub === 'prime' || !opp.primeOrSub ? true : false,
    source: 'SAM.gov',
    created_at: new Date().toISOString()
  }
}));

return records;

// Prepare contract record for Airtable
const enriched = $node['Enrich Contract Data'].json;
const scored = $node['Score Contract Opportunity'].json;

return [{
  json: {
    record_type: 'contract',
    legal_name: enriched?.legal_name || $node['Parse SAM.gov Records'].json?.legal_name || 'Unknown',
    business_email: enriched?.business_email || $node['Parse SAM.gov Records'].json?.contact_email || '',
    phone: enriched?.phone || $node['Parse SAM.gov Records'].json?.contact_phone || '',
    county: enriched?.county || '',
    score: scored?.score || 0,
    priority: scored?.priority || 'medium',
    pipeline_status: 'pending',
    icebreaker: scored?.icebreaker || `Opportunity identified on SAM.gov. Estimated value: $${$node['Parse SAM.gov Records'].json?.estimated_value || '0'}. Deadline: ${$node['Parse SAM.gov Records'].json?.deadline || 'TBD'}.`,
    segment: scored?.segment || 'Government/GovCon',
    service_fit: scored?.service_fit || 0.8,
    ticket_estimate: $node['Parse SAM.gov Records'].json?.estimated_value || 0,
    agency: $node['Parse SAM.gov Records'].json?.agency || 'Unknown',
    total_obligated_amount: $node['Parse SAM.gov Records'].json?.estimated_value || 0,
    teaming_email_draft: `Regarding SAM.gov Opportunity ID: ${$node['Parse SAM.gov Records'].json?.opportunity_id || 'N/A'}\n\nWe are interested in partnering on this opportunity as a ${$node['Parse SAM.gov Records'].json?.prime_contractor ? 'prime contractor' : 'subcontractor'}.`,
    event_type: 'Contract Opportunity',
    event_date: $node['Parse SAM.gov Records'].json?.deadline || new Date().toISOString(),
    source: 'SAM.gov',
    sam_opportunity_id: $node['Parse SAM.gov Records'].json?.opportunity_id || ''
  }
}];

// Log completion
return [{
  json: {
    status: 'success',
    message: `Contract opportunity saved to Airtable`,
    opportunity_id: $node['Prepare Contract Record'].json?.sam_opportunity_id || 'unknown',
    timestamp: new Date().toISOString()
  }
}];
